#{stopDate} AS stopDate,

	#{equalType} AS equalType,


	NULL AS equalType,


	#{typesStr} AS typesStr,


	NULL AS typesStr


	, #{depFatherId} AS depFatherId


	, NULL AS depFatherId


	, #{status} AS status


	, NULL AS status

, IFNULL((
	select SUM(ndgss.nx_dgss_rest_subtotal)
	from nx_distributer_goods_shelf_stock as ndgss
	where ndgss.nx_dgss_nx_dis_goods_id = dg.nx_distributer_goods_id
	and ndgss.nx_dgss_nx_distributer_id = #{disId}
	and ndgss.nx_dgss_rest_weight > 0

