		and ndgss.nx_dgss_nx_department_father_id = #{depFatherId}


		and ndgss.nx_dgss_date >= #{startDate}


		and ndgss.nx_dgss_date <= #{stopDate}

), 0) AS goodsStockTotal,
IFNULL((
	select SUM(ndgss.nx_dgss_rest_weight)
	from nx_distributer_goods_shelf_stock as ndgss
	where ndgss.nx_dgss_nx_dis_goods_id = dg.nx_distributer_goods_id
	and ndgss.nx_dgss_nx_distributer_id = #{disId}
	and ndgss.nx_dgss_rest_weight > 0

