		and ndgss.nx_dgss_date >= #{startDate}


		and ndgss.nx_dgss_date <= #{stopDate}

), 0) AS goodsStockWeightTotal
from nx_distributer_goods as dg
where dg.nx_distributer_goods_id in (
	select distinct ndgss.nx_dgss_nx_dis_goods_id
	from nx_distributer_goods_shelf_stock as ndgss

		left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ndgss.nx_dgss_nx_dis_goods_id
		left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id



			and ndgss.nx_dgss_nx_distributer_id = #{disId}



