	on ss.nx_distributer_goods_shelf_stock_id = ir.nx_dgssr_nx_stock_id
	and ir.nx_dgssr_type = 2


		and ir.nx_dgssr_date = #{inventoryDate}



		and ir.nx_dgssr_week = #{inventoryWeek}



		and ir.nx_dgssr_month = #{inventoryMonth}



		and ss.nx_dgss_nx_distributer_id = #{disId}


