and ss.nx_dgss_nx_shelf_goods_id in ( select nx_distributer_goods_shelf_goods_id from nx_distributer_goods_shelf_goods where nx_DGSG_shelf_id = #{shelfId} )
and ir.nx_dgssr_date = #{inventoryDate}
and ir.nx_dgssr_week = #{inventoryWeek}
and ir.nx_dgssr_month = #{inventoryMonth}
and ss.nx_dgss_rest_weight > 0 and ss.nx_dgss_status = 0
order by ss.nx_dgss_date ASC
limit #{offset}, #{limit}

