ndg.nx_distributer_goods_id, ndg.nx_dg_goods_name, ndg.nx_dg_goods_standardname, ndg.nx_dg_dfg_goods_grand_id, ndg.nx_dg_carton_unit, ndg.nx_dg_items_per_carton from nx_distributer_goods_shelf_stock as ndgss left join nx_distributer_goods as ndg on ndg.nx_distributer_goods_id = ndgss.nx_dgss_nx_dis_goods_id left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = ndg.nx_dg_dfg_goods_grand_id left join nx_distributer_father_goods as great on great.nx_distributer_father_goods_id = ndfg.nx_dfg_fathers_father_id left join nx_goods as ng_great on ng_great.nx_goods_id = great.nx_dfg_nx_goods_id left join nx_goods as ng_ndfg on ng_ndfg.nx_goods_id = ndfg.nx_dfg_nx_goods_id left join nx_goods as ng_dg on ng_dg.nx_goods_id = ndg.nx_dg_nx_goods_id
